// Mark incoming companies as new and prepare for dedup
// v8.3: Support for rescore mode - bypass dedup if _isRescore or _updateRecordId is set
const companies = $('Execute Workflow Trigger').all();
return companies.map(item => {
  const company = item.json;
  const name = company.company_name || company['Company Name'] || '';
  const source = company.source || company['VC Firm'] || 'Unknown';

  // Check if this is a rescore request (has existing record ID)
  const isRescore = company._isRescore === true || !!company._updateRecordId;

  return { 
    json: { 
      ...company, 
      _isNewCompany: !isRescore,
      _isRescore: isRescore,
      // Prepare dedup check data
      _dedupInput: {
        company: name,
        title: '',
        source: source,
        recordType: 'company'
      }
    } 
  };
});

// Log skipped duplicates for monitoring
const items = $input.all();
return items.map(item => {
  const dedupResult = item.json;
  return {
    json: {
      _skipped: true,
      _skipReason: 'cross_source_duplicate',
      _existingRecordId: dedupResult.existingRecordId,
      _allSources: dedupResult.allSources,
      _key: dedupResult.key,
      company_name: dedupResult._originalInput?.company,
      source: dedupResult._originalInput?.source
    }
  };
});

// Restore original company data for non-duplicates
const items = $input.all();
let markNewItems = [];
try { markNewItems = $('Mark as New & Prep Dedup').all(); } catch(e) { markNewItems = []; }

return items.map((item, index) => {
  const dedupResult = item.json;
  // Find matching original item by company name
  const companyName = dedupResult._originalInput?.company || '';
  const original = markNewItems.find(m => 
    (m.json.company_name || m.json['Company Name'] || '') === companyName
  );

  if (original) {
    return {
      json: {
        ...original.json,
        _dedupKey: dedupResult.key
      }
    };
  }

  // Fallback if no match
  return {
    json: {
      company_name: companyName,
      source: dedupResult._originalInput?.source,
      _dedupKey: dedupResult.key,
      _isNewCompany: true
    }
  };
});

const allItems = $input.all();
const newCompanies = [];
const existingRecords = [];

for (const item of allItems) {
  if (item.json._isNewCompany) {
    newCompanies.push(item);
  } else if (item.json.fields && item.json.fields['Company Name']) {
    existingRecords.push(item);
  } else if (item.json.id && item.json['Company Name']) {
    existingRecords.push({ json: { id: item.json.id, fields: item.json } });
  }
}

const normalize = (str) => str ? String(str).toLowerCase().replace(/[^a-z0-9]/g, '').trim() : '';

const existingMap = new Map();
for (const item of existingRecords) {
  const fields = item.json.fields || item.json;
  const name = fields['Company Name'] || '';
  const url = fields['Company URL'] || '';
  const recordId = item.json.id;
  if (name) {
    existingMap.set(normalize(name), { id: recordId, hasUrl: !!url && url.length > 0 });
  }
}

const uniqueCompanies = [];
const addedNames = new Set();

for (const company of newCompanies) {
  const name = company.json.company_name || company.json['Company Name'];
  const newUrl = company.json.company_url || company.json['Company URL'] || '';
  if (!name) continue;

  const normalizedName = normalize(name);
  if (!normalizedName || addedNames.has(normalizedName)) continue;

  const existing = existingMap.get(normalizedName);

  if (existing) {
    if (!existing.hasUrl && newUrl) {
      addedNames.add(normalizedName);
      const cleanCompany = { ...company.json };
      delete cleanCompany._isNewCompany;
      cleanCompany._updateRecordId = existing.id;
      uniqueCompanies.push({ json: cleanCompany });
    }
    continue;
  }

  addedNames.add(normalizedName);
  const cleanCompany = { ...company.json };
  delete cleanCompany._isNewCompany;
  uniqueCompanies.push({ json: cleanCompany });
}

if (uniqueCompanies.length === 0) {
  return [{ json: { _empty: true, _message: 'No new companies found' } }];
}

return uniqueCompanies;

// v8.4.14: Add __RID__ encoding for bulletproof _updateRecordId preservation
const items = $input.all();
return items.map(item => {
  const company = item.json;
  const name = company.company_name || company['Company Name'] || '';
  const updateRecordId = company._updateRecordId || '';
  // Encode record ID in query - Brave echoes this back in query.original for recovery
  const searchQuery = '"' + name + '" company funding employees series startup' + (updateRecordId ? ' __RID__' + updateRecordId + '__RID__' : '');
  return { json: { ...company, searchQuery } };
});

// v8.4.14: RESCORE FIX - Extract _updateRecordId from __RID__ encoding in query.original
// With runOnceForEachItem mode and __RID__ encoding, record ID survives HTTP request
// v8.3: March 2026 Audit fixes - Fortune 500 detection, employee 200 hard cap, data validation flags, enhanced sector detection

const braveResponse = $json;
const companyDataItems = $('Build Search Query').all();

// v8.4.14: Extract _updateRecordId from query.original (__RID__ encoding)
let extractedRecordId = null;
const queryOriginal = braveResponse?.query?.original || '';
const ridMatch = queryOriginal.match(/__RID__([^_]+)__RID__/);
if (ridMatch) {
  extractedRecordId = ridMatch[1];
}

// v8.4.15: Use $itemIndex for correct item matching in runOnceForEachItem mode
const currentIndex = typeof $itemIndex !== 'undefined' ? $itemIndex : 0;
const companyDataItem = companyDataItems[currentIndex]?.json || companyDataItems[0]?.json || {};

// Expanded PE/Growth Equity firm list (29 firms)
const peFirms = [
  'Vista Equity', 'Thoma Bravo', 'KKR', 'Blackstone', 'TPG', 'Carlyle',
  'Bain Capital', 'Silver Lake', 'Francisco Partners', 'Accel-KKR',
  'LLR Partners', 'Warburg Pincus', 'Apollo', 'Insight Partners', 'GTCR',
  'Clearlake', 'Welsh Carson', 'Providence Equity', 'Leonard Green',
  'Hellman & Friedman', 'Advent', 'Golden Gate Capital', 'TA Associates',
  'Brighton Park Capital', 'General Atlantic', 'Summit Partners', 'SoftBank Vision Fund',
  'EQT Partners', 'Permira'
];

// Fortune 500 / Large Enterprise parent companies
const fortune500Parents = [
  'Microsoft', 'Google', 'Amazon', 'Apple', 'Meta', 'Salesforce', 'Oracle',
  'IBM', 'SAP', 'Adobe', 'Cisco', 'Intel', 'Dell', 'HP', 'VMware', 'ServiceNow',
  'Workday', 'Intuit', 'Autodesk', 'Splunk', 'Atlassian', 'Zendesk', 'HubSpot',
  'Twilio', 'Datadog', 'Snowflake', 'Crowdstrike', 'Palo Alto Networks',
  'UnitedHealth', 'CVS', 'Cigna', 'Anthem', 'Humana', 'Kaiser', 'Optum',
  'JPMorgan', 'Goldman Sachs', 'Morgan Stanley', 'Bank of America', 'Wells Fargo',
  'Accenture', 'Deloitte', 'McKinsey', 'BCG', 'Bain'
];

// Helper: Parse funding amount string to numeric value
const parseFundingAmount = (amountStr, unitStr) => {
  const amount = parseFloat(amountStr);
  const unit = unitStr.toLowerCase();
  if (unit === 'billion' || unit === 'b') return amount * 1000000000;
  if (unit === 'million' || unit === 'm') return amount * 1000000;
  if (unit === 'k' || unit === 'thousand') return amount * 1000;
  return amount;
};

// Helper: Format funding for display
const formatFunding = (numeric) => {
  if (numeric >= 1000000000) return `$${(numeric / 1000000000).toFixed(1)}B`;
  if (numeric >= 1000000) return `$${(numeric / 1000000).toFixed(1)}M`;
  if (numeric >= 1000) return `$${(numeric / 1000).toFixed(0)}K`;
  return `$${numeric}`;
};

const currentYear = new Date().getFullYear();

// v8.3: HARD GATE THRESHOLDS (binary disqualifiers)
const MAX_BELIEVABLE_FUNDING = 5000000000; // $5B cap - no startup has raised more
const HARD_FUNDING_CAP = 500000000; // $500M total funding = hard DQ
const MAX_VALUATION = 500000000; // $500M valuation cap
const MIN_EMPLOYEES = 15; // Pre-CS inflection threshold
const HARD_EMPLOYEE_CAP = 200; // >200 = CS function already exists, hard DQ
const SOFT_EMPLOYEE_CAP = 150; // 150-200 = penalty zone (flag but don't DQ)

// v8.4.14: No map - runOnceForEachItem mode processes one item at a time
// companyDataItem already defined at index 0 above

// v8.4.14: Get company data from Build Search Query (single item with mode: each)
const companyData = {
  company_name: companyDataItem.company_name || companyDataItem['Company Name'],
  company_url: companyDataItem.company_url || companyDataItem['Company URL'],
  description: companyDataItem.description || companyDataItem['Company Description'],
  source: companyDataItem.source || companyDataItem['VC Firm'] || 'Unknown',
  _dedupKey: companyDataItem._dedupKey,
  _updateRecordId: companyDataItem._updateRecordId
};
const companyName = companyData.company_name || 'UNKNOWN';

// v8.4.14: Brave search results from HTTP response (single item)
const searchResults = braveResponse?.web?.results || [];
  const allText = searchResults.map(r => `${r.title || ''} ${r.description || ''}`).join(' ');

  // Extract employee count
  let employeeCount = null;
  const empMatch = allText.match(/([\d,]+)\s*(?:to\s*[\d,]+)?\s*employees?/i);
  if (empMatch) employeeCount = parseInt(empMatch[1].replace(/,/g, ''));

  // Extract funding stage
  let fundingStage = null;
  const stagePatterns = {
    'Series D': /Series\s*D/i,
    'Series C': /Series\s*C/i,
    'Series B': /Series\s*B/i,
    'Series A': /Series\s*A/i,
    'Seed': /\bSeed\b/i
  };
  for (const [stage, pattern] of Object.entries(stagePatterns)) {
    if (pattern.test(allText)) { fundingStage = stage; break; }
  }

  // Funding extraction with sanity checks
  let totalFunding = null, totalFundingRaw = null;
  const fundingCandidates = [];

  const contextualPatterns = [
    /(?:raised|secur(?:ed|es)|total funding of|funding of|announced)\s*\$([\d.]+)\s*(million|billion|M|B)/gi,
    /\$([\d.]+)\s*(million|billion|M|B)\s*(?:raised|funding|round|series)/gi,
    /series\s*[A-D]\s*(?:funding|round)?\s*(?:of)?\s*\$([\d.]+)\s*(million|billion|M|B)/gi
  ];

  for (const pattern of contextualPatterns) {
    let match;
    while ((match = pattern.exec(allText)) !== null) {
      const numeric = parseFundingAmount(match[1], match[2]);
      if (numeric <= MAX_BELIEVABLE_FUNDING && numeric >= 100000) {
        fundingCandidates.push({ numeric, raw: formatFunding(numeric), priority: 1 });
      }
    }
  }

  if (fundingCandidates.length === 0) {
    const fallbackPattern = /\$([\d.]+)\s*(million|billion|M|B)/gi;
    let match;
    while ((match = fallbackPattern.exec(allText)) !== null) {
      const numeric = parseFundingAmount(match[1], match[2]);
      if (numeric <= MAX_BELIEVABLE_FUNDING && numeric >= 100000) {
        fundingCandidates.push({ numeric, raw: formatFunding(numeric), priority: 2 });
      }
    }
  }

  if (fundingCandidates.length > 0) {
    fundingCandidates.sort((a, b) => {
      if (a.priority !== b.priority) return a.priority - b.priority;
      return b.numeric - a.numeric;
    });
    const best = fundingCandidates[0];
    totalFunding = best.numeric;
    totalFundingRaw = best.raw;
  }

  // Extract valuation (unicorn detection)
  let valuation = null, valuationRaw = null;
  if (/unicorn/i.test(allText)) {
    valuation = 1000000000;
    valuationRaw = '$1.0B (unicorn)';
  } else {
    const valuationPatterns = [
      /valued\s+at\s+\$([\d.]+)\s*(million|billion|M|B)/gi,
      /valuation\s+(?:of\s+)?\$([\d.]+)\s*(million|billion|M|B)/gi,
      /\$([\d.]+)\s*(million|billion|M|B)\s+valuation/gi
    ];
    for (const pattern of valuationPatterns) {
      let match;
      while ((match = pattern.exec(allText)) !== null) {
        const numeric = parseFundingAmount(match[1], match[2]);
        if (numeric > (valuation || 0)) {
          valuation = numeric;
          valuationRaw = formatFunding(numeric);
        }
      }
    }
  }

  // Check for PE backing
  const isPEBacked = peFirms.some(f => new RegExp(f, 'i').test(allText));
  const peBackerFound = peFirms.find(f => new RegExp(f, 'i').test(allText)) || null;

  // v8.3: Check for Fortune 500 subsidiary
  const isFortune500Subsidiary = fortune500Parents.some(parent => {
    const patterns = [
      new RegExp(`subsidiary of ${parent}`, 'i'),
      new RegExp(`owned by ${parent}`, 'i'),
      new RegExp(`part of ${parent}`, 'i'),
      new RegExp(`${parent} subsidiary`, 'i'),
      new RegExp(`${parent}'s`, 'i'),
      new RegExp(`a ${parent} company`, 'i')
    ];
    return patterns.some(p => p.test(allText));
  });
  const fortune500Parent = fortune500Parents.find(parent => {
    const patterns = [
      new RegExp(`subsidiary of ${parent}`, 'i'),
      new RegExp(`owned by ${parent}`, 'i'),
      new RegExp(`part of ${parent}`, 'i')
    ];
    return patterns.some(p => p.test(allText));
  }) || null;

  // Extract founded year
  let foundedYear = null;
  const foundMatch = allText.match(/(?:founded|established|since)\s*(?:in)?\s*(\d{4})/i);
  if (foundMatch) foundedYear = parseInt(foundMatch[1]);

  // Detect acquisition status - v8.3: Enhanced patterns
  let isAcquired = false;
  let acquiredBy = null;
  const acquirePatterns = [
    /acquired\s+by\s+([A-Z][a-zA-Z0-9\s&]+)/i,
    /([A-Z][a-zA-Z0-9\s&]+)\s+acquires?\s+/i,
    /acquisition\s+by\s+([A-Z][a-zA-Z0-9\s&]+)/i,
    /bought\s+by\s+([A-Z][a-zA-Z0-9\s&]+)/i,
    /merged\s+with\s+([A-Z][a-zA-Z0-9\s&]+)/i,
    /now\s+part\s+of\s+([A-Z][a-zA-Z0-9\s&]+)/i
  ];
  for (const pattern of acquirePatterns) {
    const match = allText.match(pattern);
    if (match) {
      isAcquired = true;
      acquiredBy = match[1]?.trim().substring(0, 50) || 'Unknown';
      break;
    }
  }
  if (!isAcquired && /\b(was acquired|has been acquired|acquired in \d{4}|formerly|shut down|shuttered|defunct|no longer operating)\b/i.test(allText)) {
    isAcquired = true;
  }

  // Detect if public company
  const isPublic = /\b(NYSE|NASDAQ|publicly traded|IPO|stock ticker|went public|NYSE:|NASDAQ:)\b/i.test(allText);

  // v8.3: Enhanced not-B2B-SaaS detection with more specific patterns
  const isBiotech = /\b(therapeutic|biologics|drug development|clinical trial|FDA approval|cell therapy|gene therapy|life sciences|pharma|pharmaceutical|biotech|drug discovery|oncology|immunotherapy)\b/i.test(allText);

  // Hardware: aquaculture, water infrastructure, climate tech hardware, oral health devices
  const isHardware = /\b(hardware|sensors|devices|robotics|manufacturing|IoT devices|chip|semiconductor|cleantech|solar|battery|EV charging|industrial equipment|physical product|aquaculture|water infrastructure|sewer|oral health device|dental device|wearable|smart home|smart building)\b/i.test(allText) && !/\b(SaaS|software platform|cloud platform|API|software-as-a-service)\b/i.test(allText);

  const isCrypto = /\b(blockchain|cryptocurrency|web3|NFT|DeFi|token|crypto|decentralized)\b/i.test(allText);
  const isConsumer = /\b(consumer app|DTC|direct-to-consumer|e-commerce|retail brand|vitamins|supplements|skincare|B2C|telehealth|patient app|consumer health|mobile app for consumers|consumer marketplace)\b/i.test(allText);
  const isHRTech = /\b(HR tech|human resources|DEI|diversity equity|workforce analytics|employee engagement|talent management|recruiting platform|HRIS|payroll|applicant tracking)\b/i.test(allText);

  // v8.3: Additional sector exclusions
  const isClimateHardware = /\b(carbon capture|clean energy hardware|solar panel|wind turbine|EV infrastructure|grid storage|climate tech hardware)\b/i.test(allText);
  const isAgTech = /\b(agriculture|farming|aquaculture|fishery|livestock|crop|agtech|ag-tech)\b/i.test(allText) && !/\b(SaaS|software|platform)\b/i.test(allText);

  const isNotB2BSaaS = isBiotech || isHardware || isCrypto || isConsumer || isHRTech || isClimateHardware || isAgTech;

  // v8.3: DATA VALIDATION FLAGS - impossible combinations that indicate bad data
  const dataFlags = [];
  if (fundingStage === 'Seed' && totalFunding && totalFunding > 20000000) {
    dataFlags.push(`Data inconsistency: Seed stage with ${totalFundingRaw} funding`);
  }
  if ((fundingStage === 'Series C' || fundingStage === 'Series D') && employeeCount && employeeCount < 10) {
    dataFlags.push(`Data inconsistency: ${fundingStage} with only ${employeeCount} employees`);
  }
  if (fundingStage === 'Series D' && totalFunding && totalFunding < 20000000) {
    dataFlags.push(`Data inconsistency: Series D with only ${totalFundingRaw} funding`);
  }

  // v8.3: TWO-TIER DISQUALIFICATION
  // Tier 1: HARD GATES (binary pass/fail) - score = 0, no Claude call
  const autoDisqualifiers = [];

  // Hard gates that completely disqualify
  if (isAcquired) autoDisqualifiers.push(`Acquired${acquiredBy ? ' by ' + acquiredBy : ''}`);
  if (isPEBacked) autoDisqualifiers.push(`PE-backed (${peBackerFound})`);
  if (isFortune500Subsidiary) autoDisqualifiers.push(`Fortune 500 subsidiary${fortune500Parent ? ' (' + fortune500Parent + ')' : ''}`);
  if (employeeCount && employeeCount > HARD_EMPLOYEE_CAP) autoDisqualifiers.push(`Too large (>${HARD_EMPLOYEE_CAP} employees: ${employeeCount}) - CS function exists`);
  if (totalFunding && totalFunding > HARD_FUNDING_CAP) autoDisqualifiers.push(`>$500M funding (${totalFundingRaw})`);
  if (valuation && valuation > MAX_VALUATION) autoDisqualifiers.push(`>$500M valuation (${valuationRaw})`);
  if (isPublic) autoDisqualifiers.push('Public company');
  if (['Series D'].includes(fundingStage)) autoDisqualifiers.push(`Late stage (${fundingStage})`);

  // Tier 2: SECTOR GATES - also hard DQ
  if (isNotB2BSaaS) {
    if (isBiotech) autoDisqualifiers.push('Biotech/pharma (not B2B SaaS)');
    else if (isHardware || isClimateHardware) autoDisqualifiers.push('Hardware/Physical product (not B2B SaaS)');
    else if (isAgTech) autoDisqualifiers.push('AgTech/Aquaculture (not B2B SaaS)');
    else if (isCrypto) autoDisqualifiers.push('Crypto/Web3 (not B2B SaaS)');
    else if (isHRTech) autoDisqualifiers.push('HR Tech/DEI (not target sector)');
    else if (isConsumer) autoDisqualifiers.push('Consumer/B2C/Telehealth (not B2B SaaS)');
  }

  // Tier 3: SOFT GATES - flag but still evaluate (too early)
  if (employeeCount && employeeCount < MIN_EMPLOYEES) autoDisqualifiers.push(`Too early (<${MIN_EMPLOYEES} employees: ${employeeCount})`);

  // Tier 4: WARNING FLAGS - don't disqualify but note for human review
  const warnings = [];
  if (employeeCount && employeeCount >= SOFT_EMPLOYEE_CAP && employeeCount <= HARD_EMPLOYEE_CAP) {
    warnings.push(`Employee count ${employeeCount} in penalty zone (${SOFT_EMPLOYEE_CAP}-${HARD_EMPLOYEE_CAP})`);
  }
  if (dataFlags.length > 0) {
    warnings.push(...dataFlags);
  }

  return {
    json: {
      company_name: companyData.company_name || companyData['Company Name'],
      company_url: companyData.company_url || companyData['Company URL'],
      description: companyData.description || companyData['Company Description'],
      source: companyData.source || companyData['VC Firm'] || 'Unknown',
      funding_stage: fundingStage,
      total_funding: totalFundingRaw,
      total_funding_numeric: totalFunding,
      valuation: valuationRaw,
      valuation_numeric: valuation,
      employee_count: employeeCount,
      pe_backed: isPEBacked,
      pe_backer: peBackerFound,
      is_fortune500_subsidiary: isFortune500Subsidiary,
      fortune500_parent: fortune500Parent,
      founded_year: foundedYear,
      is_acquired: isAcquired,
      acquired_by: acquiredBy,
      is_public: isPublic,
      is_biotech: isBiotech,
      is_hardware: isHardware || isClimateHardware,
      is_agtech: isAgTech,
      is_crypto: isCrypto,
      is_consumer: isConsumer,
      is_hrtech: isHRTech,
      investors: peBackerFound || '',
      autoDisqualifiers,
      disqualify_reasons: autoDisqualifiers.join('; '),
      isAutoDisqualified: autoDisqualifiers.length > 0,
      warnings: warnings,
      data_flags: dataFlags,
      _dedupKey: companyData._dedupKey,
      // v8.4.14: Use RID from query first (survives HTTP), fallback to index lookup
      _updateRecordId: extractedRecordId || companyData._updateRecordId
    }
  };

// Prepare dedup registration for auto-disqualified record
const airtableRecord = $json;
let parseData = {};
try { parseData = $('Parse Enrichment').item?.json || {}; } catch(e) { parseData = {}; }

const normalize = (str) => str ? str.toLowerCase().replace(/[^a-z0-9]/g, '').trim() : '';
const company = parseData.company_name || '';
const key = `company:${normalize(company)}`;

return {
  json: {
    key: key,
    company: company,
    title: '',
    source: parseData.source || 'Unknown',
    recordType: 'company',
    airtableRecordId: airtableRecord.id
  }
};

// v8.4.15: RESCORE FIX - Add _companyRef for ref-based lookup in Parse Persona
const items = $input.all();

const systemPrompt = `You are classifying companies by their PRIMARY customer persona.

Classify as ONE of:
- "business-user": End users are non-technical business professionals (sales, marketing, HR, finance, operations, healthcare providers, legal, executives)
- "developer": End users are primarily developers, engineers, DevOps, SRE, data engineers, or highly technical practitioners
- "mixed": Both personas are equally important primary users

Signals for DEVELOPER-AS-CUSTOMER:
- API-first products
- Developer tools, SDKs, CLI tools
- Infrastructure, observability, monitoring
- Data engineering, ETL, data pipelines
- DevOps, CI/CD, deployment
- Code review, testing, debugging tools
- Database tools, query engines
- "Built for engineers" or "by developers, for developers"

Signals for BUSINESS-USER-CUSTOMER:
- "No code required", "Self-serve", "Non-technical users"
- Sales enablement, CRM, marketing tools
- HR, recruiting, finance, legal tools
- Healthcare provider workflows
- Business intelligence for business users
- Customer support, success platforms

Respond with ONLY one word: business-user, developer, or mixed`;

return items.map(item => {
  const c = item.json;
  // v8.4.15: Create unique ref for each company to enable ref-based lookup
  const companyRef = c._updateRecordId || c.company_name || 'unknown';
  const userPrompt = `Company: ${c.company_name}\nDescription: ${c.description || 'No description available'}\nURL: ${c.company_url || 'N/A'}`;

  return {
    json: {
      ...c,
      _companyRef: companyRef,
      _personaPrompt: { systemPrompt, userPrompt }
    }
  };
});

// v8.4.15: RESCORE FIX - Use runOnceForEachItem mode with ref-based lookup
// This ensures each Claude response is matched to correct company data
const response = $json;

// v8.4.15: Build Map of company data by ref for O(1) lookup
const promptItems = $('Build Persona Prompt').all();
const companyByRef = new Map();
for (const item of promptItems) {
  const ref = item.json._companyRef || item.json._updateRecordId || item.json.company_name;
  if (ref) companyByRef.set(ref, item.json);
}

// v8.4.15: Get current item index and try to match company data
const currentIndex = $itemIndex;
let companyData = promptItems[currentIndex]?.json || {};

// v8.4.15: Verify we got the right company using ref matching
const expectedRef = companyData._companyRef || companyData._updateRecordId;
if (!expectedRef) {
  // Fallback: try to find by _updateRecordId if available
  console.log('v8.4.15 WARNING: No ref found for index', currentIndex);
}

// Enterprise motion signals that indicate a developer tool might still be a fit
const enterpriseSignals = [
  /\bSOC\s*2\b/i,
  /\bHIPAA\b/i,
  /\bcompliance\b/i,
  /\benterprise\s*(customers?|clients?|plan|pricing|tier|sales)/i,
  /\bFortune\s*500\b/i,
  /\bFortune\s*1000\b/i,
  /\bsales\s*team\b/i,
  /\baccount\s*executives?\b/i,
  /\bSSO\b/i,
  /\bSAML\b/i,
  /\bmulti-tenant\b/i,
  /\bself-hosted\b/i,
  /\bon-prem(ise)?\b/i,
  /\bcontract\s*value\b/i,
  /\bACV\b/i,
  /\bARR\b/i,
  /\bsecurity\s*review\b/i,
  /\bprocurement\b/i,
  /\bvendor\s*management\b/i
];

// Parse persona from Claude response
let persona = 'unknown';
try {
  const content = response.content?.[0]?.text || '';
