const enterpriseSignalCount = matchedSignals.length;

// Get employee count
const employeeCount = companyData.employee_count || 0;

// Determine if developer company qualifies for exception
// Exception: 50+ employees AND 2+ enterprise signals
const isDeveloperTool = persona === 'developer';
const hasEnterpriseException = isDeveloperTool && employeeCount >= 50 && enterpriseSignalCount >= 2;

// Developer auto-pass decision:
// - Developer persona + <50 employees → auto-pass
// - Developer persona + 50+ employees but <2 enterprise signals → auto-pass
// - Developer persona + 50+ employees + 2+ enterprise signals → proceed (exception)
// - Business-user or mixed → proceed
const shouldAutoPass = isDeveloperTool && !hasEnterpriseException;

let autoPassReason = null;
if (shouldAutoPass) {
  if (employeeCount < 50) {
    autoPassReason = `Developer-as-customer (${employeeCount || 'unknown'} employees) - not at enterprise scale`;
  } else {
    autoPassReason = `Developer-as-customer with ${employeeCount} employees but only ${enterpriseSignalCount} enterprise signals (need 2+)`;
  }
}

// Remove the _personaPrompt to clean up
const { _personaPrompt, ...cleanData } = companyData;

return {
  json: {
    ...cleanData,
    customer_persona: persona,
    enterprise_signal_count: enterpriseSignalCount,
    has_enterprise_exception: hasEnterpriseException,
    developer_auto_pass: shouldAutoPass,
